#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    bool isCyclic(vector<vector<int>>& graph) {
        int numVertices = graph.size();
        vector<bool> visited(numVertices, false);
        for (int node = 0; node < numVertices; node++) {
            if (!visited[node]) {
                if (dfs(node, -1, visited, graph)) {
                    return true;
                }
            }
        }
        return false;
    }
private:
    bool dfs(int node, int parent, vector<bool>& visited, vector<vector<int>>& graph) {
        visited[node] = true;
        for (int neighbor : graph[node]) {
            if (!visited[neighbor]) {
                if (dfs(neighbor, node, visited, graph)) {
                    return true;
                }
            } else if (neighbor != parent) {
                return true;
            }
        }
        return false;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int v, e;
    if (!(cin >> v >> e)) return 0;
    vector<vector<int>> graph(v);
    for (int i = 0; i < e; i++) {
        int u, w;
        if (!(cin >> u >> w)) return 0;
        graph[u].push_back(w);
        graph[w].push_back(u);
    }
    Solution sol;
    bool ans = sol.isCyclic(graph);
    cout << (ans ? "True" : "False") << "\n";
    return 0;
}
